installation.script:
#!/bin/sh
apk add --no-cache curl git go
cd /mnt/server
if [ ! -f main.go ]; then
cat << 'EOF' > main.go
package main

import (
	"fmt"
	"net/http"
)

func main() {
	fmt.Println("Server started on :8080")
	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		fmt.Fprintf(w, "Hello from Pterodactyl Golang!")
	})
	http.ListenAndServe(":8080", nil)
}
EOF
fi
